mapper.select:
SELECT COUNT(1) FROM (
    SELECT A.NOTICE_ID, A.TITLE, A.NOTICE_TYPE, A.USE_YN, A.START_DT, A.END_DT, A.VIEW_CNT, A.REG_DTTM
    FROM SMS.NOTICE A
    WHERE 1=1

            AND A.TITLE LIKE '%' || #{searchKeyword} || '%'


            AND A.NOTICE_TYPE = #{noticeType}


            AND A.USE_YN = #{useYn}


            AND A.REG_DTTM  >=  TO_TIMESTAMP(#{startDt} || '000000', 'YYYYMMDDHH24MISS')

) A

SELECT A.* FROM ( SELECT A.NOTICE_ID, A.TITLE, A.NOTICE_TYPE, A.USE_YN, A.START_DT, A.END_DT, A.VIEW_CNT, A.REG_DTTM FROM SMS.NOTICE A WHERE 1=1
AND A.TITLE LIKE '%' || #{searchKeyword} || '%'
AND A.NOTICE_TYPE = #{noticeType}
AND A.USE_YN = #{useYn}
AND A.REG_DTTM >= TO_TIMESTAMP(#{startDt} || '000000', 'YYYYMMDDHH24MISS')
) A
ORDER BY A.REG_DTTM DESC, A.NOTICE_ID DESC OFFSET #{offset} ROWS FETCH NEXT #{size} ROWS ONLY
